import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import { Button, H1, H2, InputGroup, Tooltip } from "@blueprintjs/core";
import { observer } from "mobx-react";
import Session from "../services/Session";
import { Intent } from "@blueprintjs/core/lib/esm/common/intent";

export const Login: FunctionComponent = () => {
  const [showPassword, setShowPassword] = useState(false);
  // const test: string = ctx.store.menu;
  const lockButton = (
    <Tooltip content={`${showPassword ? "Hide" : "Show"} Password`}>
      <Button
        className="outline-style-d"
        icon={showPassword ? "unlock" : "lock"}
        intent={Intent.WARNING}
        minimal={true}
        onClick={() => setShowPassword(!showPassword)}
      />
    </Tooltip>
  );
  return (
    <div className="login-inputgroup fx -c">
      <InputGroup leftIcon="user" placeholder="Username" required={true} />
      <InputGroup
        placeholder="Password"
        leftIcon="key"
        rightElement={lockButton}
        type={showPassword ? "text" : "password"}
        required={true}
      />
      <Button className="outline-style-d" icon="tick-circle">
        Connection
      </Button>
    </div>
  );
};
